	Username    string    `orm:"column(username);unique"`
	DisplayName string    `orm:"column(display_name)"`
	Email       string    `orm:"column(email)"`
	Department  string    `orm:"column(department)"`
	Role        string    `orm:"column(role)"`
	CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
	Id         int64     `orm:"column(id);pk;auto"`
	UserId     int64     `orm:"column(user_id)"`
	ActionType string    `orm:"column(action_type)"`
	Resource   string    `orm:"column(resource)"`
	IpAddress  string    `orm:"column(ip_address)"`
	Duration   int       `orm:"column(duration_ms)"`
	Success    bool      `orm:"column(success)"`
	CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
	DisplayName  string
	ActionType   string
	TotalActions int
	SuccessCount int
	AvgDuration  float64
}

// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	profile := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
	}

	id, err := o.Insert(profile)
	if err != nil {
		return nil, err
	}

	profile.Id = id
	return profile, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Create placeholders for IN clause
	placeholders := strings.Repeat("?,", len(usernames))
	placeholders = placeholders[:len(placeholders)-1]

	// We use lowercase aliases for columns to match the struct fields in UserActivitySummary
	// because Beego ORM maps column names to struct fields (case-insensitive usually, but direct mapping for Raw is safer).
	// Struct: TotalActions -> SQL: totalactions
	// Struct: SuccessCount -> SQL: successcount
	// Struct: AvgDuration  -> SQL: avgduration
	query := `SELECT u.display_name, a.action_type, 
			  COUNT(*) as totalactions, 
			  SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as successcount, 
			  AVG(a.duration_ms) as avgduration
			  FROM user_activity a 
			  JOIN user_profile u ON a.user_id = u.id
			  WHERE u.username IN (` + placeholders + `) 
			  AND a.created_at BETWEEN ? AND ?`

	args := make([]interface{}, 0, len(usernames)+2)
	for _, name := range usernames {
		args = append(args, name)
	}
	args = append(args, startDate, endDate)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var summaries []UserActivitySummary
	_, err := o.Raw(query, args...).QueryRows(&summaries)
	return summaries, err
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Validate groupByField to prevent SQL injection
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, errors.New("invalid groupByField")
	}

	// Create placeholders for IN clause
	placeholders := strings.Repeat("?,", len(departments))
	placeholders = placeholders[:len(placeholders)-1]

	query := `SELECT u.` + groupByField + ` as group_value, 
			  COUNT(DISTINCT u.id) as user_count, 
			  COUNT(a.id) as total_activities
			  FROM user_profile u 
			  LEFT JOIN user_activity a ON u.id = a.user_id
			  WHERE u.department IN (` + placeholders + `)
			  GROUP BY u.` + groupByField

	args := make([]interface{}, len(departments))
	for i, dept := range departments {
		args[i] = dept
	}

	var results []orm.Params
	_, err := o.Raw(query, args...).Values(&results)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	// orm.Params is essentially map[string]interface{}
	castedResults := make([]map[string]interface{}, len(results))
	for i, r := range results {
		castedResults[i] = r
	}

	return castedResults, nil
}

